class AgentResource:
    """agent endpoints."""

    def __init__(self, core: PodEngineCore) -> None:
        self._core = core

    def ask_agent_project_podcast_relevancy(
        self,
        *,
        project_id: str,
        podcast_id: str,
        search_options: models.AskAgentProjectPodcastRelevancySearchOptionsVariant1
        | models.AskAgentProjectPodcastRelevancySearchOptionsVariant2
        | None = None,
        force_regenerate: bool | None = None,
        request_options: RequestOptions | None = None,
    ) -> models.AskAgentProjectPodcastRelevancyResponse:
        """
        Project Podcast Relevancy

        Analyze the relevancy of a podcast to a project using AI
        """
        return _adapter_askAgentProjectPodcastRelevancy.validate_python(
            self._core.request(
                _DESCRIPTORS["askAgentProjectPodcastRelevancy"],
                {
                    "projectId": project_id,
                    "podcastId": podcast_id,
                    "searchOptions": search_options,
                    "forceRegenerate": force_regenerate,
                },
                request_options,
            )
        )

    def get_alternative_spellings(
        self,
        *,
        value: str,
        request_options: RequestOptions | None = None,
    ) -> models.GetAlternativeSpellingsResponse:
        """
        Alternative Spellings

        Generate phonetically plausible alternate spellings for a name or business. Useful for searching against auto-generated podcast transcripts where names are frequently misspelled.
        """
        return _adapter_getAlternativeSpellings.validate_python(
            self._core.request(_DESCRIPTORS["getAlternativeSpellings"], {"value": value}, request_options)
        )


