class PodEngine:
    """Pod Engine API client (synchronous).

    Example:
        pe = PodEngine(api_key="...")
        chart = pe.charts.get_latest_chart(chart_type="apple", country="us", category="top podcasts")
    """

    agent: AgentResource
    alerts: AlertsResource
    autocomplete: AutocompleteResource
    charts: ChartsResource
    episodes: EpisodesResource
    guest_profiles: GuestProfilesResource
    podcasts: PodcastsResource
    polling: PollingResource
    projects: ProjectsResource
    search: SearchResource
    stats: StatsResource
    teams: TeamsResource
    transcriptions: TranscriptionsResource
    usage: UsageResource

    def __init__(
        self,
        api_key: str,
        *,
        base_url: str | None = None,
        source: str = "api",
        headers: dict[str, str] | None = None,
        max_retries: int = 2,
        timeout: float | None = 60.0,
        http_client: httpx.Client | None = None,
    ) -> None:
        core = PodEngineCore(
            api_key=api_key,
            base_url=base_url,
            source=source,
            headers=headers,
            max_retries=max_retries,
            timeout=timeout,
            http_client=http_client,
        )
        self._core = core
        self.agent = AgentResource(core)
        self.alerts = AlertsResource(core)
        self.autocomplete = AutocompleteResource(core)
        self.charts = ChartsResource(core)
        self.episodes = EpisodesResource(core)
        self.guest_profiles = GuestProfilesResource(core)
        self.podcasts = PodcastsResource(core)
        self.polling = PollingResource(core)
        self.projects = ProjectsResource(core)
        self.search = SearchResource(core)
        self.stats = StatsResource(core)
        self.teams = TeamsResource(core)
        self.transcriptions = TranscriptionsResource(core)
        self.usage = UsageResource(core)

    def close(self) -> None:
        self._core.close()

    def __enter__(self) -> "PodEngine":
        return self

    def __exit__(self, *exc: object) -> None:
        self.close()


class AsyncPodEngine:
    """Pod Engine API client (asynchronous).

    Example:
        pe = AsyncPodEngine(api_key="...")
        chart = await pe.charts.get_latest_chart(chart_type="apple", country="us", category="top podcasts")
    """

    agent: AsyncAgentResource
    alerts: AsyncAlertsResource
    autocomplete: AsyncAutocompleteResource
    charts: AsyncChartsResource
    episodes: AsyncEpisodesResource
    guest_profiles: AsyncGuestProfilesResource
    podcasts: AsyncPodcastsResource
    polling: AsyncPollingResource
    projects: AsyncProjectsResource
    search: AsyncSearchResource
    stats: AsyncStatsResource
    teams: AsyncTeamsResource
    transcriptions: AsyncTranscriptionsResource
    usage: AsyncUsageResource

    def __init__(
        self,
        api_key: str,
        *,
        base_url: str | None = None,
        source: str = "api",
        headers: dict[str, str] | None = None,
        max_retries: int = 2,
        timeout: float | None = 60.0,
        http_client: httpx.AsyncClient | None = None,
    ) -> None:
        core = AsyncPodEngineCore(
            api_key=api_key,
            base_url=base_url,
            source=source,
            headers=headers,
            max_retries=max_retries,
            timeout=timeout,
            http_client=http_client,
        )
        self._core = core
        self.agent = AsyncAgentResource(core)
        self.alerts = AsyncAlertsResource(core)
        self.autocomplete = AsyncAutocompleteResource(core)
        self.charts = AsyncChartsResource(core)
        self.episodes = AsyncEpisodesResource(core)
        self.guest_profiles = AsyncGuestProfilesResource(core)
        self.podcasts = AsyncPodcastsResource(core)
        self.polling = AsyncPollingResource(core)
        self.projects = AsyncProjectsResource(core)
        self.search = AsyncSearchResource(core)
        self.stats = AsyncStatsResource(core)
        self.teams = AsyncTeamsResource(core)
        self.transcriptions = AsyncTranscriptionsResource(core)
        self.usage = AsyncUsageResource(core)

    async def aclose(self) -> None:
        await self._core.aclose()

    async def __aenter__(self) -> "AsyncPodEngine":
        return self

    async def __aexit__(self, *exc: object) -> None:
        await self.aclose()
